mapper.select:
/** 문제은행 게시판 리스트 */ SELECT a.* ,(select user_nm from t_user_info where user_id = a.reg_id) reg_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg1_seq) ctg1_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg2_seq) ctg2_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg3_seq) ctg3_nm FROM t_question a where 1=1
ORDER BY REG_DE DESC
LIMIT #{firstIndex},#{rowCnt}

/** 문제은행 리스트,문제검색용도 */ SELECT a.* ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg1_seq) ctg1_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg2_seq) ctg2_nm ,(select ctg_nm from t_qstn_category where qstn_ctg_seq = a.ctg3_seq) ctg3_nm ,(select user_nm from t_user_info where user_id = a.reg_id) reg_nm FROM t_question a left join (select * from t_test_question where test_tmpl_seq = #{testTmplSeq}) b on a.qstn_seq = b.qstn_seq where 1=1 and b.qstn_seq is null
and a.qstn_nm like concat('%',#{srchWrd},'%')
and a.ctg1_seq = #{srchCtg1Seq}
and a.ctg2_seq = #{srchCtg2Seq}
and a.ctg3_seq = #{srchCtg3Seq}
ORDER BY REG_DE DESC
